package main

import (
    "fmt"
    "errors"
)

// ---- The error interface ----
// type error interface {
//     Error() string
// }

// ---- Custom error type ----
type PlayerError struct {
    PlayerName string
    Code       int
    Message    string
}

func (e PlayerError) Error() string {
    return fmt.Sprintf("[%d] Player '%s': %s", e.Code, e.PlayerName, e.Message)
}

// ---- Another custom error ----
type GameError struct {
    Operation string
    Err       error
}

func (e GameError) Error() string {
    return fmt.Sprintf("game error in %s: %v", e.Operation, e.Err)
}

func (e GameError) Unwrap() error {
    return e.Err
}

// ---- Error functions ----
func findPlayer(name string) (string, error) {
    if name == "" {
        return "", PlayerError{
            PlayerName: name,
            Code:       400,
            Message:    "empty player name",
        }
    }
    if name == "Hero" {
        return "Found Hero", nil
    }
    return "", PlayerError{
        PlayerName: name,
        Code:       404,
        Message:    "player not found",
    }
}

func processPlayer(name string) (string, error) {
    result, err := findPlayer(name)
    if err != nil {
        return "", GameError{
            Operation: "processPlayer",
            Err:       err,
        }
    }
    return result, nil
}

func main() {
    // ---- Custom error with fields ----
    fmt.Println("=== Custom Error ===")

    _, err := findPlayer("Gandalf")
    if err != nil {
        fmt.Println("Error:", err)

        // Type assertion to access fields
        if pe, ok := err.(PlayerError); ok {
            fmt.Printf("Code: %d, Player: %s, Message: %s\n",
                pe.Code, pe.PlayerName, pe.Message)
        }
    }

    // ---- Wrapped error ----
    fmt.Println("\n=== Wrapped Error ===")

    _, err2 := processPlayer("Aragorn")
    if err2 != nil {
        fmt.Println("Error:", err2)

        // Unwrap the error
        if ge, ok := err2.(GameError); ok {
            fmt.Println("Operation:", ge.Operation)
            fmt.Println("Underlying error:", ge.Err)
        }
    }

    // ---- errors.Is and errors.As ----
    fmt.Println("\n=== errors.Is and errors.As ===")

    err3 := PlayerError{
        PlayerName: "Hero",
        Code:       404,
        Message:    "not found",
    }

    // Check if error is a specific type
    var pe PlayerError
    if errors.As(err3, &pe) {
        fmt.Printf("Is PlayerError: %+v\n", pe)
    }

    // ---- Error equality ----
    err4 := errors.New("something went wrong")
    err5 := errors.New("something went wrong")

    fmt.Println("err4 == err5:", err4 == err5)  // false
    fmt.Println("err4.Error() == err5.Error():", err4.Error() == err5.Error())  // true
}

